  for (const PerRouteHeaderMutation& route_config : route_configs_) {
    route_config.mutations().mutateResponseHeaders(headers, context,
                                                   encoder_callbacks_->streamInfo());
  }

  return Http::FilterHeadersStatus::Continue;
}

