1244→void FilterManager::encodeHeaders(ActiveStreamEncoderFilter* filter, ResponseHeaderMap& headers,
  1245→                                  bool end_stream) {
  1246→  // See encodeHeaders() comments in envoy/http/filter.h for why the 1xx precondition holds.
  1247→  ASSERT(!CodeUtility::is1xx(Utility::getResponseStatus(headers)) ||
  1248→         Utility::getResponseStatus(headers) == enumToInt(Http::Code::SwitchingProtocols));
  1249→  filter_manager_callbacks_.resetIdleTimer();
  1250→  disarmRequestTimeout();
  1251→
  1252→  // Headers filter iteration should always start with the next filter if available.
  1253→  StreamEncoderFilters::Iterator entry =
  1254→      commonEncodePrefix(filter, end_stream, FilterIterationStartState::AlwaysStartFromNext);
  1255→  StreamEncoderFilters::Iterator continue_data_entry = encoder_filters_.end();
  1256→
  1257→  for (; entry != encoder_filters_.end(); entry++) {
  1258→    ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
  1259→    ASSERT(!(state_.filter_call_state_ & FilterCallState::EncodeHeaders));
  1260→    state_.filter_call_state_ |= FilterCallState::EncodeHeaders;
  1261→    (*entry)->end_stream_ = (end_stream && continue_data_entry == encoder_filters_.end());
  1262→    if ((*entry)->end_stream_) {
  1263→      state_.filter_call_state_ |= FilterCallState::EndOfStream;
