        Http::CodeStats& code_stats = httpContext().codeStats();
        code_stats.chargeBasicResponseStat(cluster_->statsScope(), stats_.stat_names_.retry_,
                                           static_cast<Http::Code>(response_code),
                                           exclude_http_code_stats_);

